  // AQ 4.25: HHL & Linear Systems
  "4_25_1": { q: "HHL algorithm solves which problem?", options: ["Database search", "Linear systems of equations Ax = b", "Factoring", "None"], answer: 1, explanation: "Quantum matrix inversion.", clue: "<b>HHL</b>: Ax=b." },
