  "4_25_5": { q: "Matrices in HHL must be ____ and well-conditioned:", options: ["Dense", "Hermitian (or embedded in one)", "Empty", "None"], answer: 1, explanation: "Input requirement.", clue: "<b>A</b>: Hermitian." },
  "4_25_6": { q: "Condition number κ measures:", options: ["Temperature", "How close a matrix is to being singular/difficult to invert", "Size", "None"], answer: 1, explanation: "Affects runtime scaling.", clue: "<b>Condition</b>: Hardness metric." },
  "4_25_7": { q: "Application of HHL:", options: ["Machine Learning", "Structural Engineering/Fluid Dynamics", "Weather", "All of above"], answer: 3, explanation: "Broad use for differential equations.", clue: "<b>Scope</b>: Math models." },
  "4_25_8": { q: "Why is HHL difficult for current hardware?", options: ["Needs too many ancillas", "High depth and need for controlled-rotations", "Too fast", "None"], answer: 1, explanation: "Circuit complexity.", clue: "<b>Status</b>: Future-ready." },
  "4_25_9": { q: "HHL complexity depends on:", options: ["Qubit count", "Dimension, Sparsity, and Condition Number", "Colors", "None"], answer: 1, explanation: "Scaling factors.", clue: "<b>Scaling</b>: Dim/Sparsity." },
