  // AQ 4.26: Error Correction (Basics)
  "4_26_1": { q: "No-Cloning Theorem implies we cannot:", options: ["Delete qubits", "Copy an unknown quantum state perfectly", "Measure states", "None"], answer: 1, explanation: "Prevents simple redundancy like classical backups.", clue: "<b>Limit</b>: No Copying." },
  "4_26_2": { q: "Quantum Error Correction (QEC) protects against:", options: ["Bit flips AND Phase flips", "Only bit flips", "Heat", "Deleting files"], answer: 0, explanation: "Must handle two types of basic errors.", clue: "<b>Target</b>: X and Z." },
  "4_26_3": { q: "The 'Shor Code' uses ____ physical qubits to store 1 logical qubit:", options: ["3", "7", "9", "5"], answer: 2, explanation: "The first code to handle both flip types.", clue: "<b>Shor Code</b>: 9." },
  "4_26_4": { q: "The 'Steane Code' uses ____ qubits for 1 logical qubit:", options: ["3", "7", "9", "5"], answer: 1, explanation: "7-qubit CSS code.", clue: "<b>Steane</b>: 7." },
  "4_26_5": { q: "A 'Logical Qubit' is:", options: ["A very smart qubit", "A collection of noisy physical qubits behaving as one stable qubit", "An ancilla", "None"], answer: 1, explanation: "Encoded information.", clue: "<b>Logical</b>: Stable." },
  "4_26_6": { q: "Stabilizer formalism maps QEC to which math?", options: ["Group theory", "Calculus", "Geometry", "None"], answer: 0, explanation: "Using Pauli group operators.", clue: "<b>Math</b>: Group theory." },
  "4_26_7": { q: "Syndrome measurement reveals ____ without destroying information:", options: ["The full state", "What error happened (but not the data itself)", "The answer", "None"], answer: 1, explanation: "Parity-like checks.", clue: "<b>Syndrome</b>: Error ID." },
  "4_26_8": { q: "Surface Codes are popular because they require:", options: ["Global connectivity", "Only nearest-neighbor connectivity on a 2D lattice", "Laser cooling", "None"], answer: 1, explanation: "Hardware friendly layout.", clue: "<b>Surface</b>: Local." },
  "4_26_9": { q: "Decoders in QEC run on:", options: ["Quantum chip", "Classical hardware (fast processing of syndromes)", "Cloud", "None"], answer: 1, explanation: "MWPM or Neural decoders.", clue: "<b>Decoder</b>: Classical." },
  "4_26_10": { q: "The 'Code Distance' d means a code can correct up to ____ errors:", options: ["d", "d-1/2", "(d-1)/2", "None"], answer: 2, explanation: "Standard metric of robustness.", clue: "<b>Dist</b>: Half-way." },

  // AQ 4.27: Fault Tolerance
  "4_27_1": { q: "Fault tolerance ensures that errors:", options: ["Never happen", "Do not spread/propagate uncontrollably during gates", "Are deleted", "None"], answer: 1, explanation: "Managing cascading failures.", clue: "<b>Control</b>: Containment." },
  "4_27_2": { q: "A 'Transversal Gate' is fault tolerant because:", options: ["It's fast", "It acts bit-wise within codes and doesn't spread errors between physical qubits in a block", "It's small", "None"], answer: 1, explanation: "Structural isolation.", clue: "<b>Transversal</b>: Isolated." },
  "4_27_3": { q: "Magic State Distillation is used to implement which gate?", options: ["X", "H", "T gate", "None"], answer: 2, explanation: "T is hard to do transversally; needs magic.", clue: "<b>Magic</b>: T gate." },
  "4_27_4": { q: "Threshold theorem says if error p < p_th, we can reach ____:", options: ["Absolute zero", "Arbitrarily low logical error rate", "Infinite speed", "None"], answer: 1, explanation: "Enabling long-scale computation.", clue: "<b>Victory</b>: Low error." },
  "4_27_5": { q: "A 'Logical Gate' operates on:", options: ["A physical bit", "Encoded logical qubits", "Registers", "None"], answer: 1, explanation: "Acting on the code space.", clue: "<b>Logical</b>: Encoded." },
  "4_27_6": { q: "Qiskit's QEC research tool is called:", options: ["Terra", "Qiskit QEC / Ignis (Legacy)", "Aqua", "None"], answer: 1, explanation: "Modular tools for error analysis.", clue: "<b>Tool</b>: QEC/Ignis." },
  "4_27_7": { q: "Can we have 'Fault-Tolerant' measurement?", options: ["No", "Yes, by repeating or using flag qubits", "Only for 1 bit", "None"], answer: 1, explanation: "Handling measurement noise.", clue: "<b>M</b>: Robust." },
  "4_27_8": { q: "A 'Distance-3' code corrects how many errors?", options: ["0", "1", "2", "3"], answer: 1, explanation: "(3-1)/2 = 1.", clue: "<b>D3</b>: 1 error." },
  "4_27_9": { q: "The enemy of fault tolerance is ____ error propagation:", options: ["Slow", "High-weight (affecting many qubits at once)", "Linear", "None"], answer: 1, explanation: "Risking total system failure.", clue: "<b>Risk</b>: Cascading." },
  "4_27_10": { q: "Real-time QEC requires a ____ loop:", options: ["Long", "Tightly coupled (Low latency)", "Infinite", "None"], answer: 1, explanation: "Correcting before the next gate.", clue: "<b>Loop</b>: Fast." },

